external_knowledge:
- 'testers' refers to users who have participated in sessions of type 'testing';
- 'grades of confidence' refers to the average confidence scores calculated from eye-tracking data;
- 'filed results' refers to sessions with session_id present in the data_files table;
- 'recorded data point' means at least one entry in the eye_tracking_data table for the user.

sql:
SELECT pupil_dilation
FROM eye_tracking_data
WHERE user_id = 1;

SELECT COUNT(DISTINCT movement)
FROM eye_tracking_data
WHERE movement = '0';

SELECT session_id, AVG(pupil_dilation) AS avg_pupil_dilation, AVG(blink_rate) AS avg_blink_rate
FROM eye_tracking_data
GROUP BY session_id;
